<template>
  <view class="address-edit">
    <!-- 表单 -->
    <view class="form">
      <!-- 收货人 -->
      <view class="form-item">
        <text class="form-item__label">收货人</text>
        <input
          class="form-item__input"
          v-model="form.receiverName"
          placeholder="请输入收货人姓名"
          maxlength="20"
        />
      </view>

      <!-- 联系电话 -->
      <view class="form-item">
        <text class="form-item__label">联系电话</text>
        <input
          class="form-item__input"
          v-model="form.phone"
          type="number"
          placeholder="请输入联系电话"
          maxlength="11"
        />
      </view>

      <!-- 省市区 -->
      <picker mode="region" :value="regionValue" @change="onRegionChange">
        <view class="form-item">
          <text class="form-item__label">所在地区</text>
          <view class="form-item__picker">
            <text :class="['form-item__picker-text', { 'form-item__picker-text--placeholder': !regionText }]">
              {{ regionText || '请选择省市区' }}
            </text>
            <text class="form-item__arrow">></text>
          </view>
        </view>
      </picker>

      <!-- 详细地址 -->
      <view class="form-item">
        <text class="form-item__label">详细地址</text>
        <input
          class="form-item__input"
          v-model="form.detail"
          placeholder="请输入详细地址（街道、门牌号等）"
          maxlength="100"
        />
      </view>

      <!-- 设为默认 -->
      <view class="form-item form-item--switch">
        <text class="form-item__label">设为默认地址</text>
        <switch
          :checked="form.isDefault"
          color="#ff6600"
          @change="onSwitchChange"
        />
      </view>
    </view>

    <!-- 保存按钮 -->
    <view class="save-section">
      <view class="save-btn" @click="handleSave">
        <text class="save-btn__text">保存</text>
      </view>
    </view>
  </view>
</template>

<script>
import { getAddressList, addAddress, updateAddress } from '@/api/address'

export default {
  data() {
    return {
      isEdit: false,
      addressId: null,
      form: {
        receiverName: '',
        phone: '',
        province: '',
        city: '',
        district: '',
        detail: '',
        isDefault: false
      },
      regionValue: []
    }
  },

  computed: {
    regionText() {
      if (this.form.province && this.form.city && this.form.district) {
        return `${this.form.province} ${this.form.city} ${this.form.district}`
      }
      return ''
    }
  },

  onLoad(options) {
    if (options.id) {
      this.isEdit = true
      this.addressId = options.id
      uni.setNavigationBarTitle({ title: '编辑地址' })
      this.loadAddressDetail()
    } else {
      uni.setNavigationBarTitle({ title: '新增地址' })
    }
  },

  methods: {
    // 加载地址详情（编辑模式）
    async loadAddressDetail() {
      try {
        uni.showLoading({ title: '加载中' })
        const res = await getAddressList()
        if (res.code === 200) {
          const address = (res.data || []).find(item => item.id == this.addressId)
          if (address) {
            this.form = {
              receiverName: address.receiverName || '',
              phone: address.phone || '',
              province: address.province || '',
              city: address.city || '',
              district: address.district || '',
              detail: address.detail || '',
              isDefault: !!address.isDefault
            }
            this.regionValue = [address.province, address.city, address.district]
          }
        }
      } catch (e) {
        console.error('加载地址详情失败', e)
      } finally {
        uni.hideLoading()
      }
    },

    // 省市区选择回调
    onRegionChange(e) {
      const value = e.detail.value
      this.form.province = value[0]
      this.form.city = value[1]
      this.form.district = value[2]
      this.regionValue = value
    },

    // 默认地址开关
    onSwitchChange(e) {
      this.form.isDefault = e.detail.value
    },

    // 表单验证
    validate() {
      if (!this.form.receiverName.trim()) {
        uni.showToast({ title: '请输入收货人姓名', icon: 'none' })
        return false
      }
      if (!this.form.phone.trim()) {
        uni.showToast({ title: '请输入联系电话', icon: 'none' })
        return false
      }
      if (!/^1[3-9]\d{9}$/.test(this.form.phone)) {
        uni.showToast({ title: '请输入正确的手机号', icon: 'none' })
        return false
      }
      if (!this.form.province || !this.form.city || !this.form.district) {
        uni.showToast({ title: '请选择所在地区', icon: 'none' })
        return false
      }
      if (!this.form.detail.trim()) {
        uni.showToast({ title: '请输入详细地址', icon: 'none' })
        return false
      }
      return true
    },

    // 保存地址
    async handleSave() {
      if (!this.validate()) return

      try {
        uni.showLoading({ title: '保存中' })
        const data = {
          receiverName: this.form.receiverName.trim(),
          phone: this.form.phone.trim(),
          province: this.form.province,
          city: this.form.city,
          district: this.form.district,
          detail: this.form.detail.trim(),
          isDefault: this.form.isDefault ? 1 : 0
        }

        let res
        if (this.isEdit) {
          data.id = this.addressId
          res = await updateAddress(data)
        } else {
          res = await addAddress(data)
        }

        if (res.code === 200) {
          uni.showToast({ title: '保存成功', icon: 'success' })
          setTimeout(() => {
            uni.navigateBack()
          }, 1000)
        } else {
          uni.showToast({ title: res.message || '保存失败', icon: 'none' })
        }
      } catch (e) {
        uni.showToast({ title: '保存失败', icon: 'none' })
      } finally {
        uni.hideLoading()
      }
    }
  }
}
</script>

<style lang="scss" scoped>
.address-edit {
  min-height: 100vh;
  background-color: $bg-color;
  padding: $spacing-sm;
}

/* 表单 */
.form {
  background-color: $bg-color-white;
  border-radius: $border-radius-md;
  overflow: hidden;
}

.form-item {
  display: flex;
  align-items: center;
  padding: $spacing-md;
  border-bottom: 1rpx solid $border-color-light;

  &:last-child {
    border-bottom: none;
  }

  &--switch {
    justify-content: space-between;
  }

  &__label {
    font-size: $font-size-md;
    color: $text-color;
    width: 160rpx;
    flex-shrink: 0;
  }

  &__input {
    flex: 1;
    font-size: $font-size-md;
    color: $text-color;
  }

  &__picker {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  &__picker-text {
    font-size: $font-size-md;
    color: $text-color;

    &--placeholder {
      color: $text-color-placeholder;
    }
  }

  &__arrow {
    font-size: $font-size-md;
    color: $text-color-lighter;
  }
}

/* 保存按钮 */
.save-section {
  margin-top: $spacing-xl;
}

.save-btn {
  background-color: $primary-color;
  border-radius: $border-radius-round;
  padding: $spacing-md;
  text-align: center;

  &__text {
    font-size: $font-size-md;
    color: #ffffff;
    font-weight: bold;
  }
}
</style>
